class CacheMetrics:
    def __init__(self, redis_client):
        self.redis = redis_client
    
    def get_info(self) -> Dict[str, Any]:
        try:
            info = self.redis.info()
            return {
                'connected_clients': info.get('connected_clients', 0),
                'used_memory': info.get('used_memory_human', '0'),
                'total_commands_processed': info.get('total_commands_processed', 0),
                'keyspace_hits': info.get('keyspace_hits', 0),
                'keyspace_misses': info.get('keyspace_misses', 0),
                'uptime_in_seconds': info.get('uptime_in_seconds', 0)
            }
        except Exception as e:
            logger.error(f"Failed to get Redis info: {e}")
            return {}
    
    def get_hit_rate(self) -> float:
        try:
            info = self.redis.info()
            hits = info.get('keyspace_hits', 0)
            misses = info.get('keyspace_misses', 0)
            total = hits + misses
            if total == 0:
                return 0.0
            return (hits / total) * 100
        except Exception as e:
            logger.error(f"Failed to calculate hit rate: {e}")
            return 0.0


class DistributedCacheMicroservice:
    def __init__(self, connection_type='cluster', **kwargs):
        self.connection_manager = RedisConnectionManager(connection_type, **kwargs)
        self.redis_client = self.connection_manager.get_client()
        self.cache = SecureDataCache(self.redis_client)
        self.metrics = CacheMetrics(self.redis_client)
        
    def health_check(self) -> Dict[str, Any]:
        is_healthy = self.connection_manager.ping()
        return {
            'status': 'healthy' if is_healthy else 'unhealthy',
            'redis_connected': is_healthy,
            'metrics': self.metrics.get_info() if is_healthy else {}
        }
    
    def get_cache(self) -> SecureDataCache:
        return self.cache
    
    def get_metrics(self) -> CacheMetrics:
        return self.metrics


